function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    let maxProfit = originalProfit;

    const halfK = k / 2;
    const prefixDiff = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        const original = strategy[i] * prices[i];
        let modified = 0;
        if (i < halfK) {
            modified = 0 * prices[i];
        } else {
            modified = 1 * prices[i];
        }
        prefixDiff[i + 1] = prefixDiff[i] + (modified - original);
    }

    let maxDiff = 0;
    for (let i = k; i <= n; i++) {
        const currentDiff = prefixDiff[i] - prefixDiff[i - k];
        if (currentDiff > maxDiff) {
            maxDiff = currentDiff;
        }
    }

    return originalProfit + maxDiff;
}
